  5→
  6→use config::{PVM_BINARY, label_addr};
  7→use cor24_emulator::EmulatorCore;
  8→use demos::{DEMOS, RUNTIME_SPC};
  9→use gloo::timers::callback::Timeout;
 10→use web_sys::{HtmlInputElement, HtmlSelectElement};
 11→use yew::prelude::*;
 12→
 13→const BATCH_SIZE: u64 = 50_000;
 14→const TICK_MS: u32 = 25;
 15→
 16→/// P-code instruction size lookup (opcode byte → total size in bytes).
 17→fn pcode_instr_size(op: u8) -> u32 {
 18→    match op {
 19→        // IMM24 (4 bytes): push, jmp, jz, jnz, call, loadg, storeg, addrg
 20→        0x01 | 0x30 | 0x31 | 0x32 | 0x33 | 0x54 | 0x55 | 0x56 => 4,
 21→        // IMM8 (2 bytes): push_s, ret, ret_v, trap, enter, loadl, storel,
 22→        //                  loada, storea, addrl, sys
 23→        0x02 | 0x34 | 0x35 | 0x36 | 0x40 | 0x42 | 0x43 | 0x44 | 0x45 | 0x57 | 0x60 => 2,
 24→        // D8_O8 (3 bytes): loadn, storen
 25→        0x58 | 0x59 => 3,
 26→        // D8_A24 (5 bytes): calln
 27→        0x5A => 5,
 28→        // NONE (1 byte): everything else
 29→        _ => 1,
 30→    }
 31→}
 32→
 33→#[derive(Clone, Copy, PartialEq)]
 34→enum AppStatus {
 35→    Ready,
 36→    Running,
 37→    Exited,
 38→}
 39→
 40→pub enum Msg {
 41→    SelectDemo(usize),
 42→    LinkAndRun,
 43→    Stop,
 44→    Tick,
 45→    ToggleSwitch,
 46→    UpdateInput(String),
 47→    SendInput,
 48→    InputKeyDown(KeyboardEvent),
 49→}
 50→
 51→pub struct App {
 52→    selected: usize,
 53→    status: AppStatus,
 54→    emulator: EmulatorCore,
 55→    output: String,
 56→    running: bool,
 57→    halted: bool,
 58→    instruction_count: u64,
 59→    binary_size: usize,
 60→    led_on: bool,
 61→    switch_on: bool,
 62→    uart_input: String,
 63→    uart_rx_queue: VecDeque<u8>,
 64→    _tick_handle: Option<Timeout>,
 65→    pending_code_base: Option<u32>,
 66→    vm_state_addr: u32,
 67→    vm_loop_addr: u32,
 68→    code_seg_addr: u32,
 69→}
 70→
 71→impl App {
 72→    fn load_vm_binary(&mut self) {
 73→        self.emulator = EmulatorCore::new();
 74→        for (i, &b) in PVM_BINARY.iter().enumerate() {
 75→            self.emulator.write_byte(i as u32, b);
 76→        }
 77→    }
 78→
 79→    fn load_p24_image(&mut self, image: &pa24r::LoadedImage) {
 80→        let load_addr = 0x010000_u32;
 81→        let code_size = image.code.len() as u32;
 82→        let total = code_size + image.data.len() as u32;
 83→
 84→        // Write code + data contiguously at load_addr
 85→        for (i, &b) in image.code.iter().chain(image.data.iter()).enumerate() {
 86→            self.emulator.write_byte(load_addr + i as u32, b);
 87→        }
 88→
 89→        // Relocate data references in push IMM24 instructions
 90→        let mut i: u32 = 0;
 91→        while i < code_size {
 92→            let op = self.emulator.read_byte(load_addr + i);
 93→            let size = pcode_instr_size(op);
 94→            if op == 0x01 && i + 4 <= code_size {
 95→                let lo = self.emulator.read_byte(load_addr + i + 1) as u32;
 96→                let mid = self.emulator.read_byte(load_addr + i + 2) as u32;
 97→                let hi = self.emulator.read_byte(load_addr + i + 3) as u32;
 98→                let val = lo | (mid << 8) | (hi << 16);
 99→                if val >= code_size && val < total {
100→                    let abs = val + load_addr;
101→                    self.emulator.write_byte(load_addr + i + 1, abs as u8);
102→                    self.emulator
103→                        .write_byte(load_addr + i + 2, (abs >> 8) as u8);
104→                    self.emulator
105→                        .write_byte(load_addr + i + 3, (abs >> 16) as u8);
106→                }
107→            }
108→            i += size;
109→        }
110→
111→        self.binary_size = total as usize;
112→        self.pending_code_base = Some(load_addr);
113→    }
114→
115→    fn apply_pending_code_base(&mut self) {
116→        if let Some(load_addr) = self.pending_code_base.take() {
117→            // Write "sys halt" at code_seg to stop pvm.s after init
118→            self.emulator.write_byte(self.code_seg_addr, 0x60);
119→            self.emulator.write_byte(self.code_seg_addr + 1, 0x00);
120→
121→            // Run pvm.s init (boots, prints banner)
122→            self.emulator.resume();
123→            self.emulator.run_batch(10_000);
124→
125→            // Discard boot output
126→            self.emulator.clear_uart_output();
127→            self.output.clear();
128→
129→            // Soft reset preserving memory
130→            self.emulator.reset();
131→            self.emulator.set_uart_tx_busy_cycles(0);
132→
133→            // Jump to vm_loop, skip pvm.s init
134→            self.emulator.set_pc(self.vm_loop_addr);
135→            self.emulator.set_reg(3, self.vm_state_addr); // fp
136→
137→            // Patch vm_state for loaded demo
138→            let base = self.vm_state_addr;
139→            // code_base = load_addr
140→            self.emulator.write_byte(base + 18, load_addr as u8);
141→            self.emulator.write_byte(base + 19, (load_addr >> 8) as u8);
142→            self.emulator.write_byte(base + 20, (load_addr >> 16) as u8);
143→            // pc = 0
144→            self.emulator.write_byte(base, 0);
145→            self.emulator.write_byte(base + 1, 0);
146→            self.emulator.write_byte(base + 2, 0);
147→            // status = 0 (running)
148→            self.emulator.write_byte(base + 21, 0);
149→            self.emulator.write_byte(base + 22, 0);
150→            self.emulator.write_byte(base + 23, 0);
151→        }
152→    }
153→
154→    fn collect_uart(&mut self) {
155→        let uart = self.emulator.get_uart_output().to_owned();
156→        if !uart.is_empty() {
157→            self.output.push_str(&uart);
158→            self.emulator.clear_uart_output();
159→        }
160→    }
161→
162→    fn feed_uart_bytes(&mut self) {
163→        while !self.uart_rx_queue.is_empty() {
164→            let status = self.emulator.read_byte(0xFF0101);
165→            if status & 0x01 != 0 {
166→                break;
167→            }
168→            if let Some(byte) = self.uart_rx_queue.pop_front() {
169→                self.emulator.send_uart_byte(byte);
170→            }
171→        }
172→    }
173→
174→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
175→        let link = ctx.link().clone();
176→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
177→            link.send_message(Msg::Tick);
178→        }));
179→    }
180→
181→    fn check_halted(&mut self, reason: cor24_emulator::StopReason) {
182→        match reason {
183→            cor24_emulator::StopReason::Halted
184→            | cor24_emulator::StopReason::InvalidInstruction(_) => {
185→                self.halted = true;
186→                self.running = false;
187→                self._tick_handle = None;
188→                self.status = AppStatus::Exited;
189→            }
190→            _ => {}
191→        }
192→        // Also check p-code vm_state STATUS field
193→        let st = self.emulator.read_byte(self.vm_state_addr + 21) as u32
194→            | ((self.emulator.read_byte(self.vm_state_addr + 22) as u32) << 8)
195→            | ((self.emulator.read_byte(self.vm_state_addr + 23) as u32) << 16);
196→        if st != 0 {
197→            self.halted = true;
198→            self.running = false;
199→            self._tick_handle = None;
200→            self.status = AppStatus::Exited;
201→        }
202→    }
203→
204→    fn link_and_assemble(&mut self) -> Result<pa24r::LoadedImage, String> {
205→        let demo = &DEMOS[self.selected];
206→
207→        // Parse runtime and demo .spc modules
208→        let rt_module = pl24r::parser::parse(RUNTIME_SPC, "runtime.spc")
209→            .map_err(|e| format!("Parse runtime: {e}"))?;
210→        let demo_module = pl24r::parser::parse(demo.spc_source, "demo.spc")
211→            .map_err(|e| format!("Parse demo: {e}"))?;
212→
213→        // Link: runtime first, then demo (which contains main)
214→        let linked = pl24r::linker::link(&[rt_module, demo_module]).map_err(|errs| {
215→            errs.iter()
216→                .map(|e| e.to_string())
217→                .collect::<Vec<_>>()
218→                .join("; ")
219→        })?;
220→        let spc_text = pl24r::linker::emit(&linked);
221→
222→        // Assemble linked .spc to .p24 binary
223→        let p24_bytes = pa24r::assemble_to_p24(&spc_text).map_err(|errs| {
224→            errs.iter()
225→                .map(|e| format!("line {}: {}", e.line, e.message))
226→                .collect::<Vec<_>>()
227→                .join("; ")
228→        })?;
229→
230→        // Load .p24 binary
231→        pa24r::load_p24(&p24_bytes).map_err(|e| format!("Load p24: {e:?}"))
232→    }
233→}
