235→impl Component for App {
236→    type Message = Msg;
237→    type Properties = ();
238→
239→    fn create(_ctx: &Context<Self>) -> Self {
240→        let mut emulator = EmulatorCore::new();
241→        for (i, &b) in PVM_BINARY.iter().enumerate() {
242→            emulator.write_byte(i as u32, b);
243→        }
244→
245→        Self {
246→            selected: 0,
247→            status: AppStatus::Ready,
248→            emulator,
249→            output: String::new(),
250→            running: false,
251→            halted: false,
252→            instruction_count: 0,
253→            binary_size: 0,
254→            led_on: false,
255→            switch_on: false,
256→            uart_input: String::new(),
257→            uart_rx_queue: VecDeque::new(),
258→            _tick_handle: None,
259→            pending_code_base: None,
260→            vm_state_addr: label_addr("vm_state"),
261→            vm_loop_addr: label_addr("vm_loop"),
262→            code_seg_addr: label_addr("code_seg"),
263→        }
264→    }
265→
266→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
267→        match msg {
268→            Msg::SelectDemo(idx) => {
269→                if idx < DEMOS.len() {
270→                    self.selected = idx;
271→                    // Stop any running execution
272→                    self.running = false;
273→                    self.halted = false;
274→                    self._tick_handle = None;
275→                    self.output.clear();
276→                    self.instruction_count = 0;
277→                    self.binary_size = 0;
278→                    self.status = AppStatus::Ready;
279→                    self.pending_code_base = None;
280→                }
281→                true
282→            }
283→
284→            Msg::LinkAndRun => {
285→                // Reset state
286→                self.running = false;
287→                self._tick_handle = None;
288→                self.uart_rx_queue.clear();
289→                self.output.clear();
290→                self.instruction_count = 0;
291→                self.halted = false;
292→                self.led_on = false;
293→
294→                // Reload VM binary
295→                self.load_vm_binary();
296→
297→                // Link and assemble
298→                match self.link_and_assemble() {
299→                    Ok(image) => {
300→                        self.load_p24_image(&image);
301→
302→                        // Apply and start running
303→                        self.apply_pending_code_base();
304→                        self.running = true;
305→                        self.status = AppStatus::Running;
306→                        self.emulator.resume();
307→                        self.schedule_tick(ctx);
308→                    }
309→                    Err(e) => {
310→                        self.output = format!("Error: {e}");
311→                        self.status = AppStatus::Exited;
312→                    }
313→                }
314→                true
315→            }
316→
317→            Msg::Stop => {
318→                self.running = false;
319→                self._tick_handle = None;
320→                self.emulator.pause();
321→                self.status = AppStatus::Exited;
322→                true
323→            }
324→
325→            Msg::Tick => {
326→                if !self.running || self.halted {
327→                    return false;
328→                }
329→
330→                self.feed_uart_bytes();
331→                let result = self.emulator.run_batch(BATCH_SIZE);
332→                self.instruction_count += result.instructions_run;
333→                self.collect_uart();
334→
335→                // Check LED state
336→                let led_byte = self.emulator.read_byte(0xFF0200);
337→                self.led_on = led_byte != 0;
338→
339→                self.check_halted(result.reason);
340→
341→                if self.running && !self.halted {
342→                    self.schedule_tick(ctx);
343→                }
344→                true
345→            }
346→
347→            Msg::ToggleSwitch => {
348→                self.switch_on = !self.switch_on;
349→                true
350→            }
351→
352→            Msg::UpdateInput(val) => {
353→                self.uart_input = val;
354→                false
355→            }
356→
357→            Msg::SendInput => {
358→                let text = std::mem::take(&mut self.uart_input);
359→                for b in text.bytes() {
360→                    self.uart_rx_queue.push_back(b);
361→                }
362→                self.uart_rx_queue.push_back(b'\n');
363→                true
364→            }
365→
366→            Msg::InputKeyDown(e) => {
367→                if e.key() == "Enter" {
368→                    ctx.link().send_message(Msg::SendInput);
369→                }
370→                false
371→            }
372→        }
373→    }
374→
375→    fn view(&self, ctx: &Context<Self>) -> Html {
376→        let link = ctx.link();
377→        let demo = &DEMOS[self.selected];
378→
379→        let on_select = link.callback(|e: Event| {
380→            let target: HtmlSelectElement = e.target_unchecked_into();
381→            Msg::SelectDemo(target.value().parse::<usize>().unwrap_or(0))
382→        });
383→
384→        let on_input = link.callback(|e: InputEvent| {
385→            let target: HtmlInputElement = e.target_unchecked_into();
386→            Msg::UpdateInput(target.value())
387→        });
388→
389→        let on_keydown = link.callback(Msg::InputKeyDown);
390→
391→        let (status_text, status_class) = match self.status {
392→            AppStatus::Ready => ("Ready", "status status-ready"),
393→            AppStatus::Running => ("Running", "status status-running"),
394→            AppStatus::Exited => ("Exited", "status status-exited"),
395→        };
396→
397→        let can_run = !self.running;
398→        let is_running = self.running;
399→
400→        html! {
401→            <>
402→                <header>
403→                    <h1>{"Pascal Demos"}</h1>
404→                    <span class="subtitle">{"COR24 P-Code VM"}</span>
405→                </header>
406→
407→                <div class="toolbar">
408→                    <select class="demo-select" onchange={on_select}>
409→                        { for DEMOS.iter().enumerate().map(|(i, d)| html! {
410→                            <option value={i.to_string()} selected={i == self.selected}>
411→                                { d.name }
412→                            </option>
413→                        })}
414→                    </select>
415→                    if can_run {
416→                        <button class="btn btn-run"
417→                                onclick={link.callback(|_| Msg::LinkAndRun)}>
418→                            {"Link & Run"}
419→                        </button>
420→                    } else {
421→                        <button class="btn btn-stop"
422→                                onclick={link.callback(|_| Msg::Stop)}>
423→                            {"Stop"}
424→                        </button>
425→                    }
426→                    <span class={status_class}>{ status_text }</span>
427→                </div>
428→
429→                <div class="grid">
430→                    // Top-left: Pascal Source
431→                    <div class="panel panel-tl">
432→                        <div class="panel-header">{"Pascal Source"}</div>
433→                        <div class="panel-body">
434→                            <pre class="code-display">{ demo.pas_source }</pre>
435→                        </div>
436→                    </div>
437→
438→                    // Top-right: P-Code Assembly
439→                    <div class="panel panel-tr">
440→                        <div class="panel-header">{"P-Code Assembly (.spc)"}</div>
441→                        <div class="panel-body">
442→                            <pre class="code-display">{ demo.spc_source }</pre>
443→                        </div>
444→                    </div>
445→
446→                    // Bottom-left: Output
447→                    <div class="panel panel-bl">
448→                        <div class="panel-header">{"Output"}</div>
449→                        <div class="panel-body">
450→                            <div class="output-text">{ &self.output }</div>
451→                        </div>
452→                        <div class="uart-input">
453→                            <input class="uart-field" type="text"
454→                                   placeholder="UART input..."
455→                                   value={self.uart_input.clone()}
456→                                   oninput={on_input}
457→                                   onkeydown={on_keydown}
458→                                   disabled={!is_running} />
459→                            <button class="btn btn-send"
460→                                    onclick={link.callback(|_| Msg::SendInput)}
461→                                    disabled={!is_running}>
462→                                {"Send"}
463→                            </button>
464→                        </div>
465→                    </div>
466→
467→                    // Bottom-right: Hardware
468→                    <div class="panel panel-br">
469→                        <div class="panel-header">{"Hardware"}</div>
