486→                                        onclick={link.callback(|_| Msg::ToggleSwitch)}>
487→                                        { if self.switch_on { "ON" } else { "OFF" } }
488→                                    </button>
489→                                </div>
490→                            </div>
491→                            <div class="hw-section">
492→                                <div class="hw-row">
