        html! {
            <>
                <header>
                    <h1>{"Pascal Demos"}</h1>
                    <span class="subtitle">{"COR24 P-Code VM"}</span>
                </header>

                <div class="toolbar">
                    <select class="demo-select" onchange={on_select}>
                        { for DEMOS.iter().enumerate().map(|(i, d)| html! {
