    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
    padding: 2px 0;
}

.led-indicator {
    display: inline-block;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid var(--surface2);
    background: var(--surface0);
    flex-shrink: 0;
}

.led-indicator.led-on {
    background: var(--green);
    border-color: var(--green);
    box-shadow: 0 0 6px var(--green);
}

.switch-btn {
    font-family: var(--mono);
    font-size: 11px;
    padding: 2px 10px;
    background: var(--surface0);
    color: var(--overlay2);
    border: 1px solid var(--surface2);
    border-radius: 3px;
    cursor: pointer;
}

.switch-btn:hover {
    background: var(--surface1);
}

.switch-btn.switch-on {
    color: var(--peach);
    border-color: var(--peach);
}

.hw-stat {
    font-size: 12px;
    color: var(--overlay1);
    font-variant-numeric: tabular-nums;
}

.hw-stat-val {
    color: var(--text);
}

/* Footer */
footer {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 20px;
    font-size: 0.8em;
    color: var(--overlay0);
    border-top: 1px solid var(--surface1);
    flex-shrink: 0;
}

footer .sep { color: var(--surface2); }

